-- AI 生成的 shoulders 动作详情
USE fitlc;

INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('TRX侧平举', 'shoulders', 'other', 'intermediate', NULL, '1. 调整TRX悬吊带的长度，使手柄位于胸部水平位置，双脚与肩同宽站立，双手握住手柄，手臂自然下垂。\n2. 身体略微前倾，保持核心收紧，背部挺直，目光注视前方。\n3. 肩部发力，将双臂向两侧平举至与肩同高或略低于肩部，注意肘部略微弯曲，保持小臂与地面平行。\n4. 在最高点稍作停顿，感受侧三角肌的收缩，然后控制力量缓慢下放回起始位置。\n5. 重复进行8-12次，保持呼吸均匀，避免憋气。', '确保TRX悬吊带已正确固定在稳固的支撑点上，并在使用前检查扣环与把手是否有磨损。,在开始前进行肩部和上背部的热身，避免在肩关节活动受限的情况下强行举臂。,举臂时保持背部挺直、核心收紧，避免用力过猛导致肩关节受伤或腰部过度前倾。', '使用过大的摆动或借助身体惯性抬起手臂，导致侧三角肌的负荷减少。,手臂抬得过高（超过肩平面）或肘部过度伸展，增加肩峰下空间压力。,背部和脊柱在动作过程中出现弓背或过度前倾，导致腰椎负担增加。', '如果想要增加难度，可将脚位置前移，使身体倾斜角度增大；如果感到肩部不适，可适当缩短吊带长度，使手臂起始位置更低，或减少动作幅度。', 'isolation', '{"哑铃侧平举":"保持相同的起止轨迹和肘部微屈的角度，换用哑铃进行训练，可调节重量以匹配TRX的阻力感受。","弹力带侧平举":"将弹力带固定在脚下或门框上，同样以侧向抬臂完成动作，注意保持张力在全程均匀。","单手TRX侧平举":"将一侧手柄固定，单独使用另一侧手臂完成动作，以增加核心稳定性和单侧控制难度。"}', 'published', NOW(3), NOW(3));
SET @eid_380 = LAST_INSERT_ID();
