INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('TRX反向飞鸟', 'shoulders', 'other', 'intermediate', NULL, '1. 调整TRX锚点，确保固定牢固，手柄长度调至与肩同高；2. 面向锚点站立，双手握住手柄，手臂伸直，身体略微前倾，使躯干与地面约成45度角，核心收紧，背部保持平直；3. 肩胛骨向下收紧，保持肩部轻微收紧，以肩关节为轴心，向身体两侧水平展开双臂，肘部保持微屈，手掌向下或稍微向外；4. 动作到达最高点时稍作停顿，感受后肩（后三角肌）和上背部的收缩，然后控制力量缓慢回到起始姿势，手臂保持轻微弯曲；5. 重复进行规定次数，全程保持核心稳定，避免躯干晃动或耸肩。', '1. 确保TRX锚点能够承受全身重量，使用专用固定点或安全扣；2. 动作全程保持脊柱中立，避免弓背或过度前倾导致腰部压力；3. 如出现肩部疼痛或不适，应立即停止并咨询专业教练。', '1. 使用过大摆动或借力完成动作，导致后肩刺激减弱；2. 肘部下降或锁死，使肩关节受压；3. 肩胛骨未收紧，出现耸肩或胸部过度参与。', '1. 如感到力量不足，可将双脚后移，降低身体倾斜角度以减少阻力；2. 手柄长度微调，使手臂在展开时保持在肩平面以下，以更好激活后肩；3. 可改为单臂练习，提高核心稳定性需求。', 'isolation', '{"单臂版":"一次只使用单侧手臂进行，提升核心稳定性和单侧后肩力量","侧卧版":"将身体侧卧于地面进行TRX反向飞鸟，降低身体倾斜角度，减少对核心的依赖","哑铃版":"使用哑铃进行站姿反向飞鸟，转换到地面或凳子上进行，以改变负荷分配"}', 'published', NOW(3), NOW(3));
