INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('TRX推举', 'shoulders', 'other', 'intermediate', NULL, '1. 调整TRX悬吊带长度，使手柄在站立时约与胸部同高。\n2. 面向锚点，双手握住把手，脚后跟微微抬起，身体保持直立，核心收紧。\n3. 起始姿势为手臂伸展在胸前，肘部微屈，双手与肩同宽。\n4. 慢慢向上推把手，同时略微前倾身体以保持绳子张力，直到手臂完全伸直，手柄位于耳朵上方或稍高处。\n5. 在最高点稍作停顿，确保肩胛骨轻微下沉，避免耸肩。\n6. 缓慢有控制地将把手下放回到起始姿势，保持核心持续发力，避免身体晃动。', '1. 使用前检查TRX锚点、绳索和卡扣是否牢固，防止脱落。\n2. 保持核心收紧，避免下背部过度弓起，以防止腰椎受伤。\n3. 选择合适的难度重量（即合适的脚位和绳长），确保在动作全程保持控制。', '1. 动作过程中下背部拱起（核心不稳），导致腰椎压力过大。\n2. 下放时失控让身体向后摆荡，失去对肩部的张力。\n3. 绳子长度调节不当，导致肩关节活动范围受限或肩部过度前倾。', '1. 缩短绳子增加难度，伸长绳子降低难度。
2. 脚步离锚点越远，负荷越大；脚靠近锚点则负荷减小。
3. 可通过改变手柄间距（宽握或窄握）来调整肩部发力角度。', 'compound', '{"TRX Chest Press":"将手掌朝下，略微前倾身体，保持手臂伸展，直接向前推，可将肩部发力转为胸部发力。","TRX Pike":"将身体呈倒V形，双手撑在地面上，利用TRX手柄进行肩部推举，能够同时强化核心与肩部力量。","TRX Incline Press":"把脚放在稍高的平台或台阶上，身体倾斜角度减小，降低肩部负荷，更专注于胸大肌和三角肌前束。"}', 'published', NOW(3), NOW(3));
