INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('上斜哑铃推举', 'shoulders', 'dumbbell', 'intermediate', NULL, '1. 调整上斜凳的角度至30~45度，坐在凳上，双脚踏实地面，双手各持一只哑铃，手臂自然垂于两侧，手掌朝前。\n2. 将哑铃提升至肩部两侧，手肘略微低于肩部，保持手腕中立，避免手腕过度屈曲。\n3. 深吸一口气，收紧核心，在保持背部挺直的同时，将哑铃向上推举至手臂几乎伸直，注意不要锁死肘关节。\n4. 在最高点稍作停顿，感受肩部的收缩，然后呼气，缓慢将哑铃下放回至起始位置，控制在2~3秒内完成下降。\n5. 重复进行8~12次，完成设定的组数，期间保持动作连贯、节奏稳定。', '1. 在进行推举前务必进行肩部热身，避免肩袖受伤。\n2. 动作全程保持核心收紧、脊柱中立，避免腰部拱起导致下背压力。\n3. 选取合适的重量，确保在最高点能够控制哑铃，避免因重量过大而导致失去平衡或脱手。', '1. 手肘外展过大（呈90度）导致肩部受力不均。\n2. 在下降时速度过快或不做控制，冲击肩关节。\n3. 使用过重的哑铃导致肩部上提前倾，背部失去中立姿势。', '1. 若肩部柔韧性不足，可适当降低凳子倾斜角度，以减轻肩部伸展范围。
2. 若感到胸部参与过多，可将凳子角度调低或改为平板姿势。
3. 如手腕不适，可在哑铃握把处使用护腕或改为手掌相对的内旋握法。', 'compound', '{"平板哑铃推举":"将凳子调平，保持相同的动作幅度和重量，侧重胸部整体发展。","上斜哑铃飞鸟":"保持上斜角度，手臂微屈，使用更轻的哑铃，侧重胸肌上部与肩部的拉伸。","站姿哑铃推举":"在不倾斜凳子的情况下进行站姿推举，增加核心稳定性的需求。","坐姿哑铃推举":"在坐姿状态下进行，保持凳子垂直，侧重肩部前束的孤立刺激。"}', 'published', NOW(3), NOW(3));
SET @eid_335 = LAST_INSERT_ID();
-- Suggested muscle: 三角肌前束 (agonist)
-- Suggested muscle: 三角肌中束 (synergist)
-- Suggested muscle: 胸大肌（锁骨部） (synergist)
-- Suggested muscle: 三头肌（长头） (synergist)
-- Suggested muscle: 三头肌（外侧头） (stabilizer)
-- Suggested muscle: 肩袖肌群（冈上肌、冈下肌） (stabilizer)
-- Suggested muscle: 前锯肌 (stabilizer)
-- Suggested muscle: 腹直肌 (stabilizer)

INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('下斜哑铃推举', 'shoulders', 'dumbbell', 'advanced', NULL, '1. 调整平凳至下斜角度（约30-45度），双脚稳固踏在地面或踏板上，保持背部平直。\n2. 双手各持一只合适重量的哑铃，手掌朝前，手肘微弯，将哑铃抬至胸部两侧，呈起始姿势。\n3. 呼气时，主要用前三角肌和胸大肌的力量，将哑铃向上推举至手臂伸直但不完全锁死，确保肩胛骨保持收紧。\n4. 在顶峰位置稍作停顿，感受肌肉收缩，然后吸气，缓慢将哑铃下降至胸部两侧，保持肘部角度略低于肩部。\n5. 重复完成设定的次数，注意保持核心稳定，避免弓背或耸肩。', '1. 确保哑铃重量适合自身力量水平，避免在推举时出现失衡。\n2. 在动作全程保持肩胛骨收紧，避免肩部过度前伸导致受伤。\n3. 若感到肩膀或胸部疼痛，应立即停止并咨询专业教练或医生。', '1. 肘部过度外展，导致肩部承受额外压力。\n2. 推举时耸肩或使用惯性，导致动作不稳并增加受伤风险。\n3. 下放时速度过快，未能控制重量，容易造成肌肉拉伤。', '初学者可以先使用较轻的哑铃，专注于动作的全程控制；中高级训练者可逐步增加重量或采用递增组以提高负荷；若肩膀有伤病，可将凳子调至更平的角度或改用坐姿进行，以减轻肩部压力。', 'compound', '{"上斜哑铃推举":"将凳子调至上斜角度（约30-45度），重点刺激上部胸大肌和前三角肌，适合想要强化上胸的练习者。","坐姿哑铃推举":"在坐姿下进行，减少对核心的依赖，适合背部或腰部有伤的练习者。","站姿哑铃推举":"站立时完成，需要更强的核心稳定性，能够更好地激活全身协同肌群。"}', 'published', NOW(3), NOW(3));
SET @eid_336 = LAST_INSERT_ID();
