INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('交替哑铃推举', 'shoulders', 'dumbbell', 'beginner', NULL, '1. 站立，双脚与肩同宽，双手各持一只哑铃，哑铃位置与肩部平齐，手掌朝前。 2. 深吸一口气，收紧核心肌群和下背部，保持躯干直立稳定。 3. 首先将右侧哑铃向上推举，同时呼气，手臂伸直但肘关节不要完全锁死。 4. 在顶峰位置略作停顿，感受三角肌收缩，然后吸气缓慢将哑铃降回起始位置。 5. 换左侧手臂重复相同的推举动作，保持身体稳定不晃动。 6. 左右交替进行，重复指定次数，注意保持呼吸节奏与动作的协调。', '推举时保持核心收紧，避免身体过度后仰导致下背部受伤。,选择合适的重量，在动作全程保持控制，不要借助惯性完成推举。,如果感到肩关节不适，应立即停止动作并降低重量或改为坐姿练习。', '身体在推举时前后晃动或过度后仰，借用身体惯性发力。,推举时耸肩，导致肩部发力不充分且增加肩关节压力。,下降速度过快或未完全控制，降低动作效果并增加受伤风险。', '初学者建议先从较轻重量的坐姿哑铃推举开始练习，熟练掌握动作模式后再过渡到站姿。腕关节柔韧性较差的人群可以在握哑铃时略微内转手腕。肩部活动受限者可减小动作幅度，以舒适为前提逐步增加范围。', 'compound', '{"增加稳定性":"改为坐姿哑铃推举，双手同时推举，减少核心参与。","增加难度":"在推举时配合腿部动作，如在弓步姿势下进行交替推举。","孤立训练":"可改为单侧哑铃推举，专注于单侧三角肌的强化。","哑铃转杠铃":"熟悉动作后可用杠铃推举替代，负荷更大但稳定性要求更高。"}', 'published', NOW(3), NOW(3));
SET @eid_324 = LAST_INSERT_ID();
