INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('低位绳索前平举', 'shoulders', 'cable', 'intermediate', NULL, '1. 调整绳索高度至最低位置（脚踝或低滑轮），确保滑轮与肩部同高或略低。\n2. 站立于绳索前，双脚与肩同宽，膝盖微屈，保持核心收紧，背部挺直。\n3. 双手握住绳索手柄，手掌向下，手臂自然垂于身体两侧，肩胛骨稍微后收。\n4. 吸气时，用前三角肌发力，将手臂从身体前侧向上抬起至与肩同高的位置，手肘保持微屈且不锁死。\n5. 在最高点稍微停顿，感受前三角肌的收缩，然后呼气，缓慢将手臂放回起始位置，控制重量不要猛然下落。\n6. 完成预定的重复次数后，松开手柄，关闭器械，确保绳索安全复位。', '保持脊柱自然曲线，避免弓背或过度前倾，以防止下背受伤。,控制动作幅度，避免手臂抬得过高导致肩关节受压或耸肩。,使用适当的重量，确保能够完成全程动作；如果感到肩部不适，应立即停止并检查姿势。', '动作过快或使用冲力抬起重量，导致前三角肌未能充分受刺激。,手肘过度伸展或锁死，使肘关节承担额外压力。,肩部耸肩或上抬过高，导致上斜方肌过度参与，降低前三角肌的孤立效果。', '可以通过稍微向前倾斜身体来增加前三角肌的刺激，但需保持核心稳定；调整握法（掌心向上或向下）可改变前三角肌的激活程度；若肩部有伤病，可降低动作幅度或使用较轻重量并加入肩袖肌群的预热；还可以通过改变站距或使用单手操作来调节难度。', 'isolation', '{"变体类型":"低位绳索前平举可转换为哑铃前平举、杠铃前平举、站姿绳索前平举或坐姿绳索前平举。转换要点：1) 采用相同的手臂角度和抬升高度；2) 根据重量换算保持相对负荷一致；3) 保持肩胛骨稳定，避免耸肩；4) 注意动作节奏与呼吸，保持对前三角肌的持续张力。"}', 'published', NOW(3), NOW(3));
SET @eid_349 = LAST_INSERT_ID();
