-- Suggested muscle: 后三角肌 (antagonist)

INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('侧撑肩部外展', 'shoulders', 'bodyweight', 'intermediate', NULL, '1. 起始姿势：侧卧或侧撑，左手撑地，身体保持从头到脚呈一条直线，右臂自然放在体侧或胸前。\n2. 收紧核心，保持脊柱中立，肩膀、髋部和脚保持在同一平面，避免塌腰或拱背。\n3. 吸气，同时将右臂向上举至约与肩同高，手臂保持伸直，掌心向下，确保动作是由肩部外展驱动，而非耸肩。\n4. 在最高点保持1-2秒，感受中三角肌的收缩，然后呼气，缓慢控制地将右臂放回起始位置，避免猛然下落。\n5. 完成指定次数（如每侧8-12次）后，换另一侧重复相同动作。\n6. 如需进阶，可在手腕下放置不稳定的垫子，或手持轻量哑铃进行负重。', '保持核心收紧，防止腰部下沉导致脊柱过度弯曲或下背部疼痛。,若在动作过程中出现肩部疼痛或不适，应立即停止并降低强度或改为更简单的变体。,初学者应在稳固的地面上练习，避免在软垫或不平衡的表面上进行，以防侧翻或扭伤。', '身体侧向塌陷或臀部向前倾，导致脊柱失去中立姿势。,使用惯性甩臂，肩关节冲击过大，降低中三角肌的刺激效果。,外展时耸肩，使上斜方肌过度参与，削弱对中三角肌的锻炼。', '初学者可以先练习保持侧撑30秒，待核心稳定后再加入手臂外展动作。,如需降低难度，可在侧撑时将下方手臂的肘部放在软垫上，以减轻手腕压力。,若肩关节活动受限，可减小外展幅度，保持在舒适范围内，避免强迫伸展导致伤害。', 'compound', '{"变体类型":"使用弹力带进行侧撑肩部外展，将弹力带固定在下方手臂，向上拉伸以增加阻力；或者改为侧卧肩部外展，在地面上直接抬起手臂，降低核心要求。"}', 'published', NOW(3), NOW(3));
