INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('侧撑转体', 'shoulders', 'bodyweight', 'intermediate', NULL, '1. 起始姿势：侧卧在垫子上，左手撑地，手肘伸直，手掌置于肩部正下方，身体保持笔直，腿伸直叠放。\n2. 抬起臀部：收紧腹肌和臀部，使身体从肩膀到脚踝形成一条直线，呈侧撑姿势。\n3. 旋转上身：保持核心稳定，慢慢将右手向上举起，同时将上身向左侧旋转，使右手臂指向天花板，保持臀部不离地。\n4. 保持并控制：在最高点稍作停顿，感受腹斜肌和肩部的紧绷，确保动作平稳、呼吸自然。\n5. 回到起始姿势：缓慢控制身体回到侧撑姿势，然后放下手臂，换另一侧重复相同动作。', '1. 确保手腕与肩膀垂直，避免手腕过度内旋导致受伤；2. 若肩膀有不适感，可先降低动作幅度或改为跪姿侧撑；3. 动作全程保持核心紧绷，防止腰部下沉导致下背部压力过大。', '1. 臀部下沉或抬起过高，导致身体失去直线对齐；2. 旋转时肩膀前倾或耸肩，使肩部过度负荷；3. 动作速度过快，缺乏对核心的控制，容易导致拉伤。', '初学者可以将下方的手臂放在垫子上或使用墙壁进行支撑，降低难度；进阶者可以在旋转时加入哑铃或弹力带，提高肩部力量需求；若手腕不适，可将手掌改为握拳或使用前臂支撑。', 'compound', '{"俯卧撑转体":"在完成标准俯卧撑后加入侧撑转体的旋转动作，可在保持核心稳定的同时加强胸肩力量。","侧桥转体":"将侧桥动作与转体结合，从侧撑姿势直接向天花板旋转手臂，以更大幅度刺激腹斜肌。","侧卧转体":"在侧卧姿势下，仅旋转上半身而不抬起臀部，降低难度适合恢复期或肩部受限人群。","跪姿侧撑转体":"以膝盖支撑代替脚支撑，降低重心和负荷，便于初学者掌握动作轨迹。"}', 'published', NOW(3), NOW(3));
SET @eid_373 = LAST_INSERT_ID();
