INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('俯卧哑铃推举', 'shoulders', 'dumbbell', 'advanced', NULL, '1. 准备姿势：俯卧在平板凳或地面上，双手各持一只哑铃，手臂伸直，手掌朝向身体前方，肘部略微弯曲。\n2. 起始动作：吸气，收紧核心与肩胛骨，将哑铃向上推起至手臂几乎伸直，胸部略微离开支撑面，保持肩胛骨稳定。\n3. 顶峰收缩：在最高点停顿约1-2秒，感受前三角肌和胸大肌的收缩，确保肩部不出现耸肩。\n4. 下降控制：呼气，缓慢有控制地将哑铃下放至起始位置，保持肘部略低于肩部，避免弹震或过度伸展。\n5. 循环重复：根据训练计划进行所需的次数，保持全程动作的连贯性和呼吸节奏。', '1. 确保胸部和肩部在动作全程保持支撑，避免背部过度拱起。\n2. 使用适当重量的哑铃，避免超负荷导致肩关节受伤。\n3. 若感到肩部或手腕不适，应立即停止并调整姿势或请教教练。', '1. 耸肩或肩胛骨向上提，导致肩部受压。\n2. 动作过快、缺乏控制，导致肘部外展过多或冲击。\n3. 背部下沉或抬起，导致腰部过度拱起或失去核心支撑。', '1. 调整凳子角度：如果想更多刺激胸大肌，可将凳子倾斜约30度；如果想专注前三角肌，可使用平板。
2. 改变握距：握距越宽，胸大肌参与越多；握距越窄，三头肌参与越多。
3. 选择合适的哑铃重量，确保可以在全程保持正确姿势后再逐步增加负荷。', 'compound', '{"上斜俯卧哑铃推举":"将凳子倾斜30-45度，专注于上胸和前三角肌的刺激。","站姿哑铃推举":"改为站立姿势推举，增加核心稳定性和全身协调性。"}', 'published', NOW(3), NOW(3));
