INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('俯卧撑', 'shoulders', 'bodyweight', 'beginner', NULL, '1. 采用俯卧姿势，双手撑地，间距略宽于肩，手掌平放，手指向前。\n2. 身体从头到脚保持一条直线，核心收紧，臀部不要塌陷或抬高。\n3. 吸气，屈肘将身体下降至胸部接近地面，保持肘部约呈45度角，避免向外张得太大。\n4. 呼气，通过胸、肩、臂的力量将身体推起，回到起始姿势，手臂不完全伸直以保持张力。\n5. 重复动作，保持节奏平稳，可在每次推起时略微收紧肩胛骨。', '1. 保持脊柱中立，避免腰部过度下沉或拱起。\n2. 手掌位置应与肩同宽或略宽，避免手腕过度受压。\n3. 若出现肩部疼痛或不适，应立即停止并咨询专业教练。', '1. 腰部塌陷导致背部过度弯曲，增加腰椎压力。\n2. 肘部外展过大，使肩膀承受过多剪切力。\n3. 动作过快，缺少控制，容易导致关节受伤。', '如果标准俯卧撑难度过高，可先从跪姿俯卧撑或上斜俯卧撑（双手撑在高台上）开始；柔韧性较差者可使用弹力带或墙壁辅助。', 'compound', '{"变体类型":"跪姿俯卧撑、上斜俯卧撑、降速俯卧撑","转换建议":"初学者可先做跪姿或上斜俯卧撑，以减轻体重负荷；进阶后可尝试单手俯卧撑或俯卧撑降速版（每次下降保持3-5秒），逐步提升力量和控制能力。"}', 'published', NOW(3), NOW(3));
