INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('俯卧肩部收缩', 'shoulders', 'bodyweight', 'intermediate', NULL, '1. 起始姿势：俯卧在地面、长凳或训练垫上，双臂自然垂放于身体两侧，掌心朝上，额头轻触地面。双脚并拢，腿部伸直，身体从头到脚呈一条直线。\n2. 准备阶段：收紧核心肌群，保持脊椎中立位置，确保肩胛骨自然放松下沉，不要主动发力。\n3. 动作开始：将双臂从身体两侧向外展开约45度角，肘部微屈约30度，然后沿着身体侧面将双臂向后向内收缩，试图让双手在臀部正上方相遇。\n4. 收缩阶段：当双手到达臀部正上方时，肩胛骨充分向中线靠拢并下沉，形成挤压肩部的动作，感受到后三角肌和菱形肌的收缩，保持紧张1-2秒。\n5. 回程控制：缓慢控制地将双臂按原路径回到起始位置，肩胛骨回到自然位置，完成一次动作。\n6. 呼吸节奏：发力时呼气，回程时吸气，保持呼吸与动作的协调配合。', '1. 确保颈椎保持自然中立位置，不要将头抬起或过度转向一侧，以免颈椎受伤。\n2. 动作全程保持肩胛骨在正常活动范围内，避免过度耸肩或肩胛骨前伸，这可能导致肩关节压力过大。\n3. 如果感到肩部不适或疼痛，应立即停止动作并降低强度或寻求专业指导。', '1. 借助惯性快速完成动作，无法充分感受肌肉收缩，建议保持中等速度，确保肌肉全程张力。\n2. 耸肩或肩胛骨过度前伸，将压力转移到颈椎，应始终保持肩胛骨下沉并向中线收缩。\n3. 肘关节完全伸直锁死，导致力矩过大，应保持肘部微屈约30度，将发力集中在肩部。', '新手可以从较小的动作幅度开始，专注于感受后三角肌和菱形肌的收缩感觉。随着力量提升，逐渐增加收缩幅度直至双手能够充分靠拢。对于肩部活动度受限的人群，可以使用较低的平面或减少手臂外展角度。进阶练习者可以在动作顶峰增加2-3秒的等长收缩以增强效果。', 'isolation', '{"变体类型":"可转变为复合动作如俯身划船，将肩部收缩与髋关节铰链结合，增强功能性训练效果。"}', 'published', NOW(3), NOW(3));
SET @eid_374 = LAST_INSERT_ID();
