INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('俯身交替哑铃飞鸟', 'shoulders', 'dumbbell', 'advanced', NULL, '1. 起始姿势：双脚与肩同宽，膝盖微屈，臀部向后伸展，保持背部平直，眼睛注视地面。双手各握一只哑铃，手臂自然垂下，掌心相对。\n2. 预备动作：收紧核心，脊柱保持中立，避免弓背或塌腰。将哑铃略微抬起，肘部微屈，肩胛骨稍微后收，准备进入飞鸟动作。\n3. 动作执行：吸气时，缓慢将哑铃向身体两侧展开，保持肘部微屈或略低于肩部，感受后三角肌的拉伸；到达最高点时停顿1-2秒。\n4. 收回动作：呼气时，用后三角肌的力量将哑铃平稳拉回起始位置，避免使用惯性或弹力。\n5. 交替进行：完成一侧后，切换至另一侧，保持相同的动作幅度与速度，确保两侧训练量均衡。\n6. 结束姿势：完成指定次数后，轻轻放下哑铃，站立放松并进行肩部拉伸。', '保持脊柱中立，避免背部弓起或塌腰，以防止腰椎受伤。,使用适当重量，切勿为了完成次数而使用过大的负荷，以免肩关节受到过度压力。,在动作全程保持肩胛骨稳定，避免耸肩或过度后收，确保肩部肌肉在受控范围内工作。', '背部弓起或塌腰，导致腰椎受压，增加受伤风险。,使用惯性或甩动哑铃，使动作失去对后三角肌的有效刺激。,动作幅度不足，未能充分伸展或收缩后三角肌，降低训练效果。', '如果核心力量不足或腰部有不适，可在倾斜凳或瑞士球上进行俯身飞鸟，以减少腰部负担；若想增加难度，可在站姿下保持完全垂直的背部，并使用更大的动作幅度；对于肩部活动度受限的练习者，可适当调整肘部角度，保持肘部微屈即可。', 'isolation', '{"单侧俯身交替哑铃飞鸟":"专注于单侧控制，提升后三角肌的离心收缩能力，可在每侧完成相同次数后交替进行。","坐姿俯身哑铃飞鸟":"坐在倾斜凳上，保持躯干前倾，减少腰部压力，适合初学者或腰背不适者。","绳索俯身飞鸟":"使用绳索器械提供恒定的阻力，使肌肉在整个运动范围内保持张力，适合进阶训练。","站姿俯身飞鸟":"不借助凳子，要求更强的核心稳定性与肩部控制，适合经验丰富的训练者。","俯身交替哑铃侧平举":"将飞鸟与侧平举动作结合，在同一轨迹中完成，可提升中后三角肌的协同工作。"}', 'published', NOW(3), NOW(3));
