INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('俯身哑铃划船', 'shoulders', 'dumbbell', 'intermediate', NULL, '1. 双脚与肩同宽站立，双手各持一只哑铃，掌心向内。\n2. 微微屈膝，臀部向后推，上半身前倾，保持背部挺直，形成约45度的俯身姿势。\n3. 保持核心收紧，手臂自然下垂，肩胛骨略微后收。\n4. 将哑铃向上拉至胸部侧面，手肘贴近身体并向上提升，感受肩胛骨的内收和后三角肌的收缩。\n5. 在动作最高点稍作停顿，然后缓慢放下哑铃至起始位置，重复进行。\n6. 训练完毕后，将哑铃平稳放回地面或训练架。', '1. 确保背部始终挺直，避免弓背导致腰椎受伤。\n2. 使用适当重量的哑铃，防止在拉起时因重量过大导致肩关节过度负荷。\n3. 在进行俯身动作时，保持膝盖微屈，以减轻腰部压力。', '1. 背部下沉或弓背，导致腰椎受力过大。\n2. 拉起时手臂外张、手肘离体过远，降低肩胛收缩效果。\n3. 动作过快，使用惯性完成上拉，削弱目标肌肉的刺激。', '1. 初学者可先采用轻重量哑铃或无重量进行练习，待动作熟练后再逐步增加负荷。
2. 如感到腰部不适，可改为坐姿斜板哑铃划船，以减少背部压力。
3. 若想加强对后三角肌的刺激，可在拉起时将手肘略微向上抬高，使肩关节外旋。', 'compound', '{"单手俯身划船":"将动作改为单手持哑铃进行俯身划船，可更好地激活核心稳定性并纠正左右力量不对称。","斜板划船":"使用倾斜的训练凳支撑胸部，降低腰部负荷，适合背部或腰部有问题的训练者。","站姿哑铃划船":"保持直立姿势进行划船，侧重于上背部和后三角肌的协同工作，适合作为热身动作。"}', 'published', NOW(3), NOW(3));
SET @eid_326 = LAST_INSERT_ID();
