-- Suggested muscle: 肱二头肌 (synergist)
-- Suggested muscle: 前三角肌 (antagonist)

INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('倒立撑', 'shoulders', 'bodyweight', 'advanced', NULL, '1. 起始姿势：站立或靠在墙边，双手与肩同宽，手掌平放在地面上，手指略向外打开，保持肩部、手腕和手臂成一直线。\n2. 进入倒立姿势：利用踢腿或向墙靠的方式，将双腿抬离地面，身体呈倒立姿势，臀部收紧，核心保持紧绷，保持头部自然伸展，目光看向手掌前方。\n3. 下降阶段：屈肘慢慢向下降低身体，保持背部平直，避免弓背或塌腰，直至头顶轻触地面或接近地面，保持控制。\n4. 推起阶段：使用肩部和三头肌的力量，将身体向上推回起始姿势，手臂伸直，保持核心稳定，避免过度摆动。\n5. 完成一次后，恢复站立或继续进行下一组。根据个人能力可以先练习靠墙版，逐步脱离墙壁。', '1. 充分热身肩袖、三角肌和核心，避免肩部受伤。\n2. 建议在有经验的伙伴或使用墙壁支撑的情况下练习，以防失衡导致摔倒。\n3. 注意手腕的角度，避免手腕过度屈曲或外翻，最好使用手掌平贴地面的姿势。', '1. 背部弓起或塌腰，导致腰椎压力过大。\n2. 没有保持核心收紧，导致身体摇摆、失去平衡。\n3. 使用惯性或快速弹起，导致动作失去控制，容易受伤。', '1. 靠墙辅助：在练习初期，将脚靠在墙上以获得支撑，逐步减小对墙的依赖。
2. 膝上倒立撑：先将膝盖放在地面上，减小下降幅度，降低难度。
3. 负重递减：使用弹力带或斜板来减轻负荷，逐步进阶。', 'compound', '{"靠墙倒立撑":"从全倒立撑过渡到无墙倒立撑时，保持相同的动作幅度，逐步减少对墙的依赖。","膝上倒立撑":"在掌握膝上倒立撑后，可通过增加下降深度或使用单腿支撑进阶到全倒立撑。","弹力带辅助倒立撑":"使用弹力带在肩膀上提供向上支撑，帮助练习下降控制，随后逐渐降低弹力带强度。"}', 'published', NOW(3), NOW(3));
