INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('借力推举', 'shoulders', 'barbell', 'advanced', NULL, '1. 站姿，双脚与肩同宽或略宽，脚尖稍微外展，双手握杠铃，握距略大于肩宽，将杠铃置于锁骨前方并略微抬起。\n2. 收紧腹肌、背部挺直，肩胛骨下沉并略微后收，保持胸部挺起。\n3. 轻轻屈膝下蹲约10-15度（借力阶段），同时保持上半身正直，利用腿部的弹性势能为上推提供力量。\n4. 快速伸展膝关节和臀部，推动身体向上，同时将杠铃向上推举至手臂伸直，锁骨与杠铃形成一条直线，头部保持在中立位置。\n5. 在最高点锁住肘部，保持1-2秒，确保三角肌和肱三头肌完全收缩，然后匀速将杠铃下放回锁骨位置。\n6. 完成预定的次数后，平稳将杠铃放回杠铃架或使用安全杠完成动作。', '1. 必须进行充分的热身，尤其是肩部和上背部，以防止肩袖受伤。\n2. 动作全程保持核心紧绷，避免出现腰部下塌或过度拱背。\n3. 如使用较大重量，建议有经验的人员在旁做护杠或使用安全杠，以防失控。', '1. 过度依赖腿部驱动，导致肩部受力不足，动作失去对三角肌的有效刺激。\n2. 推举时肘部外展角度过大，形成‘V’形姿势，增加肩关节压力。\n3. 锁骨位置不正确，杠铃靠近颈部或远离胸骨，导致前倾或后仰。', '1. 握距可根据个人肩宽适当调整，一般略宽于肩宽能更好地分配负荷。
2. 脚距可以略宽或略窄，以找到最舒适的借力姿势，但须保持膝盖不超过脚尖。
3. 如出现手腕不适，可使用护腕或将杠铃稍微向手掌内侧移动，保持手腕中立。
4. 对于肩部活动度受限的训练者，可先使用轻重量进行“半程”借力推举，逐步提高活动范围。', 'compound', '{"哑铃推举":"将杠铃换成等重的哑铃，保持同样的借力动作和推举轨迹，可更好锻炼单侧肩部力量。","站姿无借力推举":"去掉借力阶段，仅依靠肩部和上背部力量完成推举，适合强化三角肌的孤立训练。","坐姿推举":"在坐姿推举器上进行，限制腿部的驱动，专注于肩部的力量提升。"}', 'published', NOW(3), NOW(3));
SET @eid_302 = LAST_INSERT_ID();
