INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('健身球俯卧撑', 'shoulders', 'other', 'intermediate', NULL, '1. 双手撑在健身球上，手臂伸直，身体呈一直线，双脚分开约与肩同宽，脚尖撑地。\n2. 收紧腹肌和臀部，保持核心稳定，避免臀部下沉或抬起。\n3. 屈肘，缓慢将胸部向下压向健身球，手肘略微外展约45度，保持肩胛骨自然收拢。\n4. 在胸部接近球面时，稍作停顿，感受胸大肌和前三角肌的收缩。\n5. 通过手掌推压球面，将身体推回起始姿势，手臂完全伸直，但不要锁定肘关节。\n6. 重复进行规定的次数，保持呼吸均匀，下降时吸气，推起时呼气。', '1. 确保健身球充气适度，表面无裂纹，使用前轻压检查稳固性。\n2. 动作全程保持脊柱中立，避免塌腰或弓背，以免对腰椎产生过大压力。\n3. 如出现肩部或手腕不适，应立即停止并调整姿势或降低难度。', '1. 臀部抬得过高，形成“倒V”姿势，导致肩膀负担增加。\n2. 下降时手肘外展角度过大，容易导致肩部受伤。\n3. 动作速度过快，缺少控制，容易失去核心稳定。', '1. 如感觉难度过高，可先尝试跪姿健身球俯卧撑，双膝跪地，手仍撑在球上。
2. 可选择直径较小的球或使用固定球架，提高稳定性。
3. 进阶时可将双脚放在稳定的椅子上或使用单臂进行练习。', 'compound', '{"跪姿健身球俯卧撑":"适合初学者或肩部不适时，降低上肢负荷","单臂健身球俯卧撑":"提升上肢力量与核心稳定性，适用于进阶训练"}', 'published', NOW(3), NOW(3));
SET @eid_382 = LAST_INSERT_ID();
