INSERT INTO exercises (name, category, equipment, difficulty, description, steps, safetyNotes, commonMistakes, adjustmentNotes, exerciseType, conversionGuide, status, created_at, updated_at)
VALUES ('前平举', 'shoulders', 'barbell', 'beginner', NULL, '1. 站姿准备：双脚与肩同宽，膝盖略微弯曲保持稳定，双手握住杠铃，手掌向下，握距略宽于肩部。\n2. 起始位置：将杠铃置于大腿前侧，保持背部挺直，核心收紧，肩胛骨自然下垂。\n3. 举起动作：吸气时，利用前三角肌的力量将杠铃平举至胸部高度，手肘保持微屈，避免锁死。\n4. 顶峰收缩：在最高点略作停顿，确保肩部不上抬，感受到前三角肌的充分收缩。\n5. 回落动作：呼气，缓慢控制地将杠铃下放回起始位置，保持手臂微屈，防止重力冲击。\n6. 循环练习：重复进行指定次数，完成后将杠铃安全放回杠铃架。', '- 确保握把稳固，避免杠铃滑落造成伤害。\n- 选择适当重量，避免使用过重导致肩关节受力过大。\n- 全程保持背部挺直，避免借助背部或摆动力量完成动作。', '- 使用大幅摆动或借助惯性举起重量，导致动作失去孤立刺激。\n- 手肘过度伸展或锁死，增加关节压力。\n- 耸肩或抬肩，导致肩胛骨上移，降低前三角肌的参与度。', '- 调整握距：略宽握距可以更好激活前三角肌，窄握距则会更强调肩袖肌群。
- 肘部角度：保持微屈可减轻肘关节压力，同时保持肌肉张力。
- 动作幅度：根据肩部柔韧性适度控制抬起高度，避免过度伸展导致肩部不适。', 'isolation', '{"哑铃前平举":"使用哑铃可单侧训练，便于控制轨迹，适合需要更高肩部孤立度时转换。","Cable前平举":"滑轮提供恒定阻力，帮助保持张力，尤其适合在训练中后段保持肌肉紧绷。","机械前平举":"固定轨道适合初学者，帮助学习正确的动作轨迹，避免错误姿势。"}', 'published', NOW(3), NOW(3));
SET @eid_304 = LAST_INSERT_ID();
